using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly YourDbContext _context;

        public ProductController()
        {
            _context = new YourDbContext();
        }

        public ActionResult Details(int id)
        {
            var product = _context.Products.Find(id);
            var reviews = _context.Reviews.Where(r => r.ProductId == id).ToList();

            var model = new ProductDetailsViewModel
            {
                Product = product,
                Reviews = reviews
            };

            return View(model);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(Review review)
        {
            if (ModelState.IsValid)
            {
                _context.Reviews.Add(review);
                _context.SaveChanges();
                return RedirectToAction("Details", new { id = review.ProductId });
            }

            return View("Error");
        }
    }
}

public class ProductDetailsViewModel
{
    public Product Product { get; set; }
    public List<Review> Reviews { get; set; }
}

public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string Content { get; set; }
    public DateTime CreatedAt { get; set; }
} 

@model YourNamespace.Models.ProductDetailsViewModel

<h1>@Model.Product.Name</h1>
<div>
    <h3>Reviews</h3>
    @foreach (var review in Model.Reviews)
    {
        <div>
            <p>@Html.Raw(review.Content)</p>
            <small>@review.CreatedAt.ToString("g")</small>
        </div>
    }
</div>

@using (Html.BeginForm("SubmitReview", "Product", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    @Html.HiddenFor(m => m.Product.Id)

    <div>
        <textarea name="Content" rows="4" cols="50" required></textarea>
    </div>
    <button type="submit">Submit Review</button>
}